import axios from 'axios';
import React, { useEffect, useState } from 'react';

export const Rasp = () => {
  const [rasps, setRasps] = useState([]);
  const [conflictingTeachers, setConflictingTeachers] = useState([]);

  useEffect(() => {
    axios.get("http://localhost:5555/rasps")
      .then(rasps => setRasps(rasps.data))
      .catch(err => console.log(err));
  }, []);

  useEffect(() => {
    const checkConflicts = () => {
      const teacherMap = new Map();

      rasps.forEach(item => {
        const key = `${item.day.day}-${item.time.time}`;
        const teacher = item.teacher.teacher;

        if (teacherMap.has(key)) {
          // Aynı gün ve saatte başka bir dersi var mı kontrol et
          if (teacherMap.get(key) !== teacher) {
            setConflictingTeachers(prevTeachers => [...prevTeachers, teacher]);
          }
        } else {
          teacherMap.set(key, teacher);
        }
      });
    };

    checkConflicts();
  }, [rasps]);

  return (
    <div className="bg-white px-4 pt-3 pb-4 rounded-sm border border-gray-200 flex-1">
      <strong className="text-gray-700 font-medium">Расписания</strong>
      <div className="border-x border-gray-200 rounded-sm mt-3">
        <table className="w-full text-gray-700">
          <thead>
            <tr>
              <th>Время</th>
              <th>День</th>
              <th>Предмет</th>
              <th>Группа</th>
              <th>Преподаватель</th>
              <th>Курс</th>
              <th>Кабинет</th>
            </tr>
          </thead>
          <tbody>
            {rasps.map(item => (
              <tr
                key={item._id}
                style={{ backgroundColor: conflictingTeachers.includes(item.teacher.teacher) ? 'bg-red-500' : 'white' }}
              >
                <td>{item.time.time}</td>
                <td>{item.day.day}</td>
                <td>{item.predmet.predmet}</td>
                <td>{item.group.group_number}</td>
                <td>{item.teacher.teacher}</td>
                <td>{item.group.kurs}</td>
                <td>{item.room}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};
